changeSet.sql:

CREATE UNIQUE INDEX idx_dim_org_unit_org_unit_uid ON analytics.dim_org_unit (org_unit_uid);
CREATE INDEX idx_dim_org_unit_level ON analytics.dim_org_unit (level_int);
-- GIN index for path_array (text[])
CREATE INDEX idx_dim_org_unit_path_array ON analytics.dim_org_unit USING GIN (path_array);

rollback.sql:
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_path_array;
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_level;
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_org_unit_uid;

changeSet.sql:
CREATE MATERIALIZED VIEW analytics.dim_org_unit_group AS SELECT row_number() OVER ()::bigint AS dim_org_unit_group_id, g.id AS group_id, g.uid AS group_uid, g.code, g.name AS name_default, COALESCE(g.translations, '[]'::jsonb) AS translations_jsonb, TRIM(COALESCE(analytics.translation_value(COALESCE(g.translations, '[]'::jsonb), 'en', 'name'), g.name)) AS name_en, TRIM(COALESCE(analytics.translation_value(COALESCE(g.translations, '[]'::jsonb), 'ar', 'name'), g.name)) AS name_ar, COALESCE(g.properties_map::jsonb, '{}'::jsonb) AS properties_jsonb, g.inactive, (g.created_date::timestamp) AT TIME ZONE 'UTC' AS created_at, (g.last_modified_date::timestamp) AT TIME ZONE 'UTC' AS updated_at FROM public.org_unit_group g;
CREATE UNIQUE INDEX idx_dim_org_unit_group_group_uid ON analytics.dim_org_unit_group (group_uid);
CREATE MATERIALIZED VIEW analytics.dim_org_unit_group_member AS SELECT row_number() OVER ()::bigint AS id, gm.group_id, g.uid AS group_uid, gm.org_unit_id, ou.uid AS org_unit_uid, (g.created_date::timestamp) AT TIME ZONE 'UTC' AS created_at, (g.last_modified_date::timestamp) AT TIME ZONE 'UTC' AS updated_at FROM public.org_unit_group_members gm LEFT JOIN public.org_unit_group g ON g.id = gm.group_id LEFT JOIN public.org_unit ou ON ou.id = gm.org_unit_id;
CREATE INDEX idx_dim_org_unit_group_member_org_unit_uid ON analytics.dim_org_unit_group_member (org_unit_uid); CREATE INDEX idx_dim_org_unit_group_member_group_uid ON analytics.dim_org_unit_group_member (group_uid);

rollback.sql:
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_group_member_group_uid;
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_group_member_org_unit_uid;
DROP MATERIALIZED VIEW IF EXISTS analytics.dim_org_unit_group_member;
DROP INDEX IF EXISTS analytics.idx_dim_org_unit_group_group_uid;
DROP MATERIALIZED VIEW IF EXISTS analytics.dim_org_unit_group;

changeSet.sql:
CREATE MATERIALIZED VIEW analytics.dim_team AS SELECT row_number() OVER ()::bigint AS dim_team_id, t.id AS team_id, t.uid AS team_uid, t.code, t.name AS name_default, t.activity_id, t.disabled, COALESCE(t.form_permissions, '[]'::jsonb) AS form_permissions_jsonb, (t.created_date::timestamp) AT TIME ZONE 'UTC' AS created_at, (t.last_modified_date::timestamp) AT TIME ZONE 'UTC' AS updated_at FROM public.team t;
CREATE UNIQUE INDEX idx_dim_team_team_uid ON analytics.dim_team (team_uid);
CREATE MATERIALIZED VIEW analytics.dim_team_form_permission AS SELECT row_number() OVER ()::bigint AS id, t.uid AS team_uid, t.id AS team_id, fp ->> 'form' AS form_uid, (fp -> 'permissions')::jsonb AS permissions_jsonb, (t.created_date::timestamp) AT TIME ZONE 'UTC' AS created_at, (t.last_modified_date::timestamp) AT TIME ZONE 'UTC' AS updated_at FROM public.team t, LATERAL jsonb_array_elements(COALESCE(t.form_permissions, '[]'::jsonb)) fp;
CREATE INDEX idx_dim_team_form_permission_team_uid ON analytics.dim_team_form_permission (team_uid); CREATE INDEX idx_dim_team_form_permission_form_uid ON analytics.dim_team_form_permission (form_uid);

rollback.sql:
DROP INDEX IF EXISTS analytics.idx_dim_team_form_permission_form_uid;
DROP INDEX IF EXISTS analytics.idx_dim_team_form_permission_team_uid;
DROP MATERIALIZED VIEW IF EXISTS analytics.dim_team_form_permission;
DROP INDEX IF EXISTS analytics.idx_dim_team_team_uid;
DROP MATERIALIZED VIEW IF EXISTS analytics.dim_team;

changeSet.sql:
CREATE MATERIALIZED VIEW analytics.dim_activity AS SELECT row_number() OVER ()::bigint AS dim_activity_id, a.id AS activity_id, a.uid AS activity_uid, a.code, a.name AS name_default, a.start_date::timestamp AS start_date, a.end_date::timestamp AS end_date,
a.project_id, COALESCE(a.translations, '[]'::jsonb) AS translations_jsonb, TRIM(COALESCE(analytics.translation_value(COALESCE(a.translations, '[]'::jsonb), 'en', 'name'), a.name)) AS name_en, TRIM(COALESCE(analytics.translation_value(COALESCE(a.translations, '[]'::jsonb), 'ar', 'name'), a.name)) AS name_ar, (a.created_date::timestamp) AT TIME ZONE 'UTC' AS created_at, (a.last_modified_date::timestamp) AT TIME ZONE 'UTC' AS updated_at FROM public.activity a;
CREATE UNIQUE INDEX idx_dim_activity_activity_uid ON analytics.dim_activity (activity_uid);


            CREATE INDEX IF NOT EXISTS idx_dim_option_option_set_uid ON analytics.dim_option (option_set_uid);
            CREATE INDEX IF NOT EXISTS idx_dim_team_form_permission_permissions ON analytics.dim_team_form_permission USING GIN (permissions_jsonb);
